module top_module(
   data_inverted,
   q_o);parameter g_num_bytes = 4;

   input [g_num_bytes * 8 - 1 : 0] data_inverted;
   output [g_num_bytes * 8 - 1 : 0] q_o;

   generate 
      genvar                        i, j;
      for(i=0;i<8;i=i+1)
        for(j=0;j<g_num_bytes;j=j+1)
          assign q_o[8 * (g_num_bytes-1-j) + i] = data_inverted[8 * j + i];
   endgenerate

endmodule
